import React, { useEffect, useState } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import {
  fetchFriends, fetchFriendRequests, fetchSentRequests,
  acceptFriendRequest, removeFriend,
} from '../redux/thunks/friendThunks';
import { NODE_API } from '../api/config';
import { toast } from 'react-toastify';
import './Friends.css';

const Friends = () => {
  const [tab, setTab] = useState('friends'); // friends, requests, sent
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { friends, requests, sentRequests, loading, requestsLoading } = useSelector((state) => state.friends);

  useEffect(() => {
    dispatch(fetchFriends({ skip: 0, limit: 50 }));
    dispatch(fetchFriendRequests({ skip: 0, limit: 50 }));
    dispatch(fetchSentRequests({ skip: 0, limit: 50 }));
  }, [dispatch]);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const getUserFromItem = (item) => {
    const u = item?.userId || item?.friendId || item;
    if (typeof u === 'object') return u;
    return { _id: u, firstName: 'User', lastName: '' };
  };

  const handleAccept = async (friendId) => {
    const result = await dispatch(acceptFriendRequest({ friendId, accept: true }));
    if (!result.error) {
      toast.success('Friend request accepted!');
      dispatch(fetchFriends({ skip: 0, limit: 50 }));
    } else {
      toast.error('Failed to accept request');
    }
  };

  const handleDecline = async (friendId) => {
    const result = await dispatch(acceptFriendRequest({ friendId, accept: false }));
    if (!result.error) {
      toast.info('Request declined');
    }
  };

  const handleRemove = async (friendId) => {
    if (!window.confirm('Remove this friend?')) return;
    const result = await dispatch(removeFriend({ friendId }));
    if (!result.error) {
      toast.success('Friend removed');
    } else {
      toast.error('Failed to remove friend');
    }
  };

  const renderUserCard = (item, actions) => {
    const u = getUserFromItem(item);
    const name = `${u.firstName || ''} ${u.lastName || ''}`.trim() || 'User';
    const avatar = getImageUrl(u.imageURL?.thumbnail || u.imageURL);

    return (
      <div key={u._id || Math.random()} className="friend-card">
        <div className="friend-info" onClick={() => navigate(`/user/${u._id}`)}>
          {avatar ? (
            <img src={avatar} alt="" className="friend-avatar" />
          ) : (
            <div className="friend-avatar-placeholder">
              {name[0].toUpperCase()}
            </div>
          )}
          <div className="friend-details">
            <span className="friend-name">{name}</span>
            {u.city && <span className="friend-city">📍 {u.city}</span>}
          </div>
        </div>
        <div className="friend-actions">
          {actions}
        </div>
      </div>
    );
  };

  return (
    <div className="friends-page">
      <div className="friends-header">
        <h1 className="friends-title">Friends</h1>
        <button className="friends-find-btn" onClick={() => navigate('/search')}>
          🔍 Find Friends
        </button>
      </div>

      {/* Tabs */}
      <div className="friends-tabs">
        <button
          className={`friends-tab ${tab === 'friends' ? 'active' : ''}`}
          onClick={() => setTab('friends')}
        >
          👥 My Friends
        </button>
        <button
          className={`friends-tab ${tab === 'requests' ? 'active' : ''}`}
          onClick={() => setTab('requests')}
        >
          📨 Requests
          {requests.length > 0 && <span className="friends-tab-badge">{requests.length}</span>}
        </button>
        <button
          className={`friends-tab ${tab === 'sent' ? 'active' : ''}`}
          onClick={() => setTab('sent')}
        >
          📤 Sent
        </button>
      </div>

      {/* Friends list */}
      {tab === 'friends' && (
        <div className="friends-list">
          {loading && friends.length === 0 && (
            <div className="friends-loading"><div className="page-loading-spinner" /></div>
          )}
          {!loading && friends.length === 0 && (
            <div className="friends-empty">
              <p>No friends yet</p>
              <button className="friends-empty-btn" onClick={() => navigate('/search')}>
                Find Friends
              </button>
            </div>
          )}
          {friends.map((item) => {
            const u = getUserFromItem(item);
            return renderUserCard(item, (
              <>
                <button className="friend-action-btn friend-msg-btn" onClick={() => navigate(`/chat/${u._id}`)}>
                  💬
                </button>
                <button className="friend-action-btn friend-remove-btn" onClick={() => handleRemove(u._id)}>
                  ✕
                </button>
              </>
            ));
          })}
        </div>
      )}

      {/* Requests */}
      {tab === 'requests' && (
        <div className="friends-list">
          {requestsLoading && requests.length === 0 && (
            <div className="friends-loading"><div className="page-loading-spinner" /></div>
          )}
          {!requestsLoading && requests.length === 0 && (
            <div className="friends-empty"><p>No pending requests</p></div>
          )}
          {requests.map((item) => {
            const u = getUserFromItem(item);
            return renderUserCard(item, (
              <>
                <button className="friend-action-btn friend-accept-btn" onClick={() => handleAccept(u._id)}>
                  ✓
                </button>
                <button className="friend-action-btn friend-decline-btn" onClick={() => handleDecline(u._id)}>
                  ✕
                </button>
              </>
            ));
          })}
        </div>
      )}

      {/* Sent requests */}
      {tab === 'sent' && (
        <div className="friends-list">
          {sentRequests.length === 0 && (
            <div className="friends-empty"><p>No sent requests</p></div>
          )}
          {sentRequests.map((item) =>
            renderUserCard(item, (
              <span className="friend-pending-label">⏳ Pending</span>
            ))
          )}
        </div>
      )}
    </div>
  );
};

export default Friends;
